import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import AuthLayout from '../components/auth/AuthLayout';
import axios from 'axios';

const DEPTS = ['CSE', 'ECE', 'EEE', 'MECH', 'CIVIL', 'IT', 'MBA', 'MCA'];

export default function SignUp() {
  const [role, setRole] = useState('student');
  const [routes, setRoutes] = useState([]);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const { register } = useAuth();
  const navigate = useNavigate();

  const [form, setForm] = useState({
    name: '', email: '', password: '', phone: '',
    adminSecret: '',
    rollNumber: '', department: '', year: '', section: '',
    address: '', boardingPoint: '', routeId: '', parentName: '', parentPhone: '',
  });

  useEffect(() => {
    axios.get('/routes/public').then(r => setRoutes(r.data)).catch(() => {});
  }, []);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const switchRole = (r) => {
    setRole(r);
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const payload = {
        name: form.name,
        email: form.email,
        password: form.password,
        phone: form.phone,
        role,
        ...(role === 'admin' ? { adminSecret: form.adminSecret } : {
          rollNumber: form.rollNumber,
          department: form.department,
          year: form.year,
          section: form.section,
          address: form.address,
          boardingPoint: form.boardingPoint,
          routeId: form.routeId || null,
          parentName: form.parentName,
          parentPhone: form.parentPhone,
        }),
      };

      const data = await register(payload);
      navigate(data.user.role === 'admin' ? '/admin/dashboard' : '/student/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <AuthLayout
      title="Create Account"
      subtitle="Register as a student or administrator"
      footerLink={{ text: 'Already have an account?', to: '/login', label: 'Sign in' }}
    >
      <div className="role-tabs">
        <button type="button" className={`role-tab ${role === 'student' ? 'active' : ''}`} onClick={() => switchRole('student')}>Student</button>
        <button type="button" className={`role-tab ${role === 'admin' ? 'active' : ''}`} onClick={() => switchRole('admin')}>Administrator</button>
      </div>

      {error && <div className="login-error">{error}</div>}

      <form onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label>Full Name</label>
            <input value={form.name} onChange={e => set('name', e.target.value)} required />
          </div>
          <div className="form-group">
            <label>Phone</label>
            <input value={form.phone} onChange={e => set('phone', e.target.value)} placeholder="10-digit mobile" />
          </div>
        </div>

        <div className="form-group">
          <label>Email</label>
          <input type="email" value={form.email} onChange={e => set('email', e.target.value)} placeholder="name@college.edu" required />
        </div>

        <div className="form-group">
          <label>Password</label>
          <div className="input-wrap">
            <input type={showPass ? 'text' : 'password'} value={form.password} onChange={e => set('password', e.target.value)} placeholder="Min. 6 characters" required minLength={6} />
            <button type="button" className="toggle-pass" onClick={() => setShowPass(!showPass)}>{showPass ? 'Hide' : 'Show'}</button>
          </div>
        </div>

        {role === 'admin' ? (
          <div className="form-group">
            <label>Administrator Access Code</label>
            <input type="password" value={form.adminSecret} onChange={e => set('adminSecret', e.target.value)} placeholder="Enter access code" required />
            <small className="field-hint">Required to register as an administrator</small>
          </div>
        ) : (
          <>
            <div className="form-section-title">Academic Details</div>
            <div className="form-row">
              <div className="form-group">
                <label>Roll Number</label>
                <input value={form.rollNumber} onChange={e => set('rollNumber', e.target.value)} />
              </div>
              <div className="form-group">
                <label>Department</label>
                <select value={form.department} onChange={e => set('department', e.target.value)}>
                  <option value="">Select department</option>
                  {DEPTS.map(d => <option key={d} value={d}>{d}</option>)}
                </select>
              </div>
            </div>
            <div className="form-row">
              <div className="form-group">
                <label>Year</label>
                <select value={form.year} onChange={e => set('year', e.target.value)}>
                  <option value="">Select year</option>
                  {[1, 2, 3, 4].map(y => <option key={y} value={y}>Year {y}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label>Section</label>
                <input value={form.section} onChange={e => set('section', e.target.value)} placeholder="e.g. A" />
              </div>
            </div>

            <div className="form-section-title">Transport Details</div>
            <div className="form-group">
              <label>Bus Route</label>
              <select value={form.routeId} onChange={e => set('routeId', e.target.value)}>
                <option value="">Select route (optional — admin can assign later)</option>
                {routes.map(r => (
                  <option key={r.id} value={r.id}>{r.routeNumber} — {r.routeName} (₹{r.monthlyFee}/mo)</option>
                ))}
              </select>
            </div>
            <div className="form-row">
              <div className="form-group">
                <label>Boarding Point</label>
                <input value={form.boardingPoint} onChange={e => set('boardingPoint', e.target.value)} />
              </div>
              <div className="form-group">
                <label>Parent Phone</label>
                <input value={form.parentPhone} onChange={e => set('parentPhone', e.target.value)} />
              </div>
            </div>
            <div className="form-group">
              <label>Address</label>
              <textarea rows={2} value={form.address} onChange={e => set('address', e.target.value)} />
            </div>
          </>
        )}

        <button type="submit" className="btn btn-primary btn-lg login-submit" disabled={loading}>
          {loading ? <><span className="spinner spinner-sm" /> Creating account...</> : 'Create Account'}
        </button>
      </form>
    </AuthLayout>
  );
}
